package helium314.keyboard.latin.completion

import java.util.concurrent.atomic.AtomicInteger

/**
 * Coordinates multi-word completions.
 *
 * It keeps a pool of candidates generated by a [CompletionProvider] and re-filters that pool
 * cheaply on every keystroke by the in-progress word prefix, without asking the provider to
 * regenerate. The expensive provider call happens only when the surrounding (committed) context
 * changes, and is expected to be run off the UI thread by the caller.
 *
 * This mirrors the "hide latency behind a fast filter" design: per-keystroke UI updates are an
 * O(pool) string filter, while the slow generation is debounced and its stale results are dropped
 * via an [epoch] counter that is bumped whenever the context is invalidated.
 *
 * The engine itself is intentionally free of Android and threading dependencies so it can be unit
 * tested on the JVM; the IME layer owns the debounce timer, the background thread and the view.
 */
class CompletionEngine @JvmOverloads constructor(
    private val provider: CompletionProvider,
    private val maxCandidates: Int = 3,
    private val poolSize: Int = 12,
) {
    private var pool: List<CompletionCandidate> = emptyList()
    private var poolContext: String? = null
    private var poolPrefix: String = ""
    private val epoch = AtomicInteger(0)

    /** The epoch a generation should be tagged with; compare against this to drop stale results. */
    val currentEpoch: Int get() = epoch.get()

    /** Candidates from the current pool whose first word matches [prefix], capped at [maxCandidates]. */
    @Synchronized
    fun visibleCandidates(prefix: String): List<CompletionCandidate> =
        pool.asSequence().filter { it.matchesPrefix(prefix) }.take(maxCandidates).toList()

    /**
     * Fast path, called on every keystroke. If the pool is still valid for [leftContext], returns
     * the candidates filtered by [prefix]. Returns null to signal that the caller should schedule a
     * (debounced) [regenerate]: either the committed context changed, or nothing in the pool matches
     * the current prefix any more.
     */
    fun onPrefixChanged(leftContext: String, prefix: String): List<CompletionCandidate>? {
        synchronized(this) {
            if (leftContext != poolContext) return null
            // The pool was generated for poolPrefix (the in-progress word at generation time). It is
            // only valid for prefixes that EXTEND it: e.g. a pool generated for "ti" (candidates like
            // "time is it") still serves "tim"/"time", but "t" or a divergent prefix must regenerate,
            // otherwise a mid-word pool would be served stale as the user edits the word.
            if (!prefix.startsWith(poolPrefix)) return null
        }
        val filtered = visibleCandidates(prefix)
        return filtered.ifEmpty { null }
    }

    /**
     * Slow path: (re)generate the pool for [leftContext]. Intended to be called off the UI thread.
     * Returns the epoch captured at the start; if [currentEpoch] has advanced by the time this
     * returns, the context was invalidated meanwhile and the caller should discard the result
     * instead of displaying it.
     */
    fun regenerate(leftContext: String, prefix: String, dictionaryWords: List<String> = emptyList()): GenerationResult {
        val startEpoch = epoch.get()
        // run the (potentially slow) provider OUTSIDE the lock so the fast path isn't blocked
        val generated = provider.generate(CompletionContext(leftContext, prefix, dictionaryWords), poolSize)
        synchronized(this) {
            if (epoch.get() == startEpoch) {
                pool = generated
                poolContext = leftContext
                poolPrefix = prefix
            }
        }
        return GenerationResult(startEpoch, visibleCandidates(prefix))
    }

    /**
     * Accept the word at [wordIndex] of [candidate]. Returns the text that should replace the
     * in-progress word (the first accepted word overwrites what the user already typed), and
     * invalidates the pool because the committed context is about to change.
     */
    fun accept(candidate: CompletionCandidate, wordIndex: Int): String {
        invalidate()
        return candidate.acceptedText(wordIndex)
    }

    /** Drop the pool and outstanding async work (e.g. on cursor jump, commit, or focus change). */
    @Synchronized
    fun invalidate() {
        epoch.incrementAndGet()
        pool = emptyList()
        poolContext = null
        poolPrefix = ""
    }

    /** Result of a [regenerate], tagged with the epoch it was produced under. */
    data class GenerationResult(val epoch: Int, val candidates: List<CompletionCandidate>)
}
